func collectTrustKeyStoreReport(useMock bool) map[string]any {
	report := map[string]any{"auth_method": "local_keystore"}
	if useMock {
		report["status"] = "green"
		report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
		report["keys"] = "mock"
		report["fix_hint"] = ""
		return report
	}
	records, err := trust.ListKeyRecords()
	if err != nil {
		report["status"] = "red"
		report["fix_hint"] = "Check local keystore permissions under ~/.config/pp/salesforce-headless-360/keystore."
		report["error"] = err.Error()
		return report
	}
	active := 0
	var latest time.Time
	for _, record := range records {
		if record.RetiredAt == nil {
			active++
		}
		if record.RegisteredAt.After(latest) {
			latest = record.RegisteredAt
		}
	}
	report["keys"] = len(records)
	report["active_keys"] = active
	if active == 0 {
		report["status"] = "yellow"
		report["fix_hint"] = "Run 'salesforce-headless-360-pp-cli trust register --org <alias>' before emitting signed bundles."
		return report
	}
	report["status"] = "green"
	if !latest.IsZero() {
		report["last_success_at"] = latest.UTC().Format(time.RFC3339)
	}
	report["fix_hint"] = ""
	return report
}

func collectApexCompanionReport(ctx context.Context, c interface {
	Get(string, map[string]string) (json.RawMessage, error)
}, cfg *config.Config, useMock bool) map[string]any {
	report := map[string]any{"auth_method": firstNonEmpty(cfg.AuthSource, "unknown")}
	if useMock {
		report["status"] = "green"
		report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
		report["class"] = "SF360SafeRead"
		report["fix_hint"] = ""
		return report
	}
	if cfg.AuthHeader() == "" {
		report["status"] = "yellow"
		report["fix_hint"] = "Authenticate, then run doctor again to verify the SF360SafeRead Apex companion."
		return report
	}
	raw, err := c.Get("/services/data/"+trust.APIVersion+"/tooling/query", map[string]string{
		"q": "SELECT Id, Name FROM ApexClass WHERE Name = 'SF360SafeRead' LIMIT 1",
	})
	if err != nil {
		report["status"] = "yellow"
		report["fix_hint"] = "Install the Apex companion with 'trust install-apex --org <alias>' when JWT or Bulk reads need user-scoped FLS."
		report["error"] = err.Error()
		return report
	}
	var payload struct {
		Records []struct {
			ID   string `json:"Id"`
			Name string `json:"Name"`
		} `json:"records"`
	}
	if err := json.Unmarshal(raw, &payload); err != nil {
		report["status"] = "yellow"
		report["fix_hint"] = "Doctor could not parse Apex companion status; verify SF360SafeRead in Setup."
		report["error"] = err.Error()
		return report
	}
	if len(payload.Records) == 0 {
		report["status"] = "yellow"
		report["fix_hint"] = "Install the Apex companion with 'trust install-apex --org <alias>' when JWT or Bulk reads need user-scoped FLS."
		return report
	}
	report["status"] = "green"
	report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
	report["class"] = payload.Records[0].Name
	report["fix_hint"] = ""
	return report
}

func collectLocalStoreReport(cacheAny any, useMock bool) map[string]any {
	report := map[string]any{"auth_method": "local_sqlite"}
	if useMock {
		report["status"] = "green"
		report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
		report["db_path"] = "mock"
		report["fix_hint"] = ""
		return report
	}
	cache, _ := cacheAny.(map[string]any)
	if cache == nil {
		report["status"] = "yellow"
		report["fix_hint"] = "Run 'salesforce-headless-360-pp-cli sync' to create the local SQLite store."
		return report
	}
	report["db_path"] = cache["db_path"]
	status, _ := cache["status"].(string)
	switch status {
	case "fresh":
		report["status"] = "green"
		report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
		report["fix_hint"] = ""
	case "stale":
		report["status"] = "yellow"
		report["fix_hint"] = "Run 'salesforce-headless-360-pp-cli sync' to refresh stale local rows."
	default:
		report["status"] = "yellow"
		report["fix_hint"] = "Run 'salesforce-headless-360-pp-cli sync' to hydrate the local SQLite store."
	}
	return report
}

func collectSFPassthroughReport(useMock bool) map[string]any {
	report := map[string]any{"auth_method": "sf_cli"}
	if useMock {
		report["status"] = "green"
		report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
		report["version"] = "mock >= 2.60.0"
		report["fix_hint"] = ""
		return report
	}
	path, err := exec.LookPath("sf")
	if err != nil {
		report["status"] = "yellow"
		report["fix_hint"] = "Install Salesforce CLI >= 2.60.0 to use 'auth login --sf <alias>' passthrough."
		return report
	}
	out, err := exec.Command("sf", "--version").CombinedOutput()
	if err != nil {
		report["status"] = "yellow"
		report["fix_hint"] = "Run 'sf --version' and confirm Salesforce CLI is healthy."
		report["path"] = path
		report["error"] = err.Error()
		return report
	}
	got, ok := doctorParseSemver(string(out))
	report["path"] = path
	report["version"] = strings.TrimSpace(string(out))
	if !ok || doctorVersionLess(got, [3]int{2, 60, 0}) {
		report["status"] = "yellow"
		report["fix_hint"] = "Upgrade Salesforce CLI to >= 2.60.0 before using sf auth passthrough."
		return report
	}
	report["status"] = "green"
	report["last_success_at"] = time.Now().UTC().Format(time.RFC3339)
	report["fix_hint"] = ""
	return report
}

func collectCompetingToolsReport() map[string]any {
	report := map[string]any{"auth_method": "local_mcp_registry"}
	var found []string
	for _, key := range []string{"AGENTFORCE_MCP", "SFDX_MCP"} {
		if os.Getenv(key) != "" {
			found = append(found, key)
		}
	}
	found = append(found, findCompetingMCPRegistries()...)
	if len(found) == 0 {
		report["status"] = "green"
		report["fix_hint"] = ""
		return report
	}
	report["status"] = "yellow"
	report["detected"] = found
	report["fix_hint"] = "Agentforce MCP or Salesforce DX MCP is configured locally; you may not need this CLI for tasks those servers already cover."
	return report
}

func findCompetingMCPRegistries() []string {
	home, err := os.UserHomeDir()
	if err != nil {
		return nil
	}
	paths := []string{
		filepath.Join(home, ".config", "claude-code", "mcp.json"),
		filepath.Join(home, ".claude", "mcp.json"),
		filepath.Join(home, "Library", "Application Support", "Claude", "claude_desktop_config.json"),
		filepath.Join(home, ".cursor", "mcp.json"),
	}
	var found []string
	for _, path := range paths {
		data, err := os.ReadFile(path)
		if err != nil {
			continue
		}
		lower := strings.ToLower(string(data))
		switch {
		case strings.Contains(lower, "agentforce"):
			found = append(found, "Agentforce MCP in "+path)
		case strings.Contains(lower, "salesforce") && strings.Contains(lower, "mcp"):
			found = append(found, "Salesforce DX MCP in "+path)
		case strings.Contains(lower, "sfdx"):
			found = append(found, "SFDX MCP in "+path)
		}
	}
	return found
}

func doctorParseSemver(text string) ([3]int, bool) {
	re := regexp.MustCompile(`\b(\d+)\.(\d+)\.(\d+)\b`)
	m := re.FindStringSubmatch(text)
	if len(m) != 4 {
		return [3]int{}, false
	}
	var out [3]int
	for i := 0; i < 3; i++ {
		n, err := strconv.Atoi(m[i+1])
		if err != nil {
			return [3]int{}, false
		}
		out[i] = n
	}
	return out, true
}

func doctorVersionLess(got, min [3]int) bool {
	for i := 0; i < 3; i++ {
		if got[i] != min[i] {
			return got[i] < min[i]
		}
	}
	return false
}

func renderDoctorCapability(w io.Writer, label string, rep map[string]any) {
	status, _ := rep["status"].(string)
	indicator := green("OK")
	switch status {
	case "yellow":
		indicator = yellow("WARN")
	case "red":
		indicator = red("FAIL")
	}
	fmt.Fprintf(w, "  %s %s: %s\n", indicator, label, status)
	for _, key := range []string{"auth_method", "last_success_at", "rows", "keys", "active_keys", "class", "path", "version", "scopes", "reason", "detected", "fix_hint"} {
		if v, ok := rep[key]; ok && fmt.Sprintf("%v", v) != "" {
			fmt.Fprintf(w, "    %s: %v\n", key, v)
		}
	}
}

func doctorSetenv(key, value string) func() {
	oldValue, hadOldValue := os.LookupEnv(key)
	_ = os.Setenv(key, value)
	return func() {
		if hadOldValue {
			_ = os.Setenv(key, oldValue)
			return
		}
		_ = os.Unsetenv(key)
	}
}

// doctorExitForFailOn returns a non-nil error when the report's worst
// status meets or exceeds the --fail-on threshold. "error" always trips
// when any section reports an error; "stale" also trips when the cache
// section is stale. The default empty string means never fail on status.
func doctorExitForFailOn(failOn string, report map[string]any) error {
	if failOn == "" {
		return nil
	}
	worstError := false
	worstStale := false
	for _, v := range report {
		s, ok := v.(string)
		if ok {
			if strings.Contains(s, "error") || strings.Contains(s, "unreachable") || strings.Contains(s, "invalid") {
				worstError = true
			}
		}
		if m, ok := v.(map[string]any); ok {
			if st, _ := m["status"].(string); st == "error" || st == "red" {
				worstError = true
			} else if st == "stale" {
				worstStale = true
			}
		}
	}
	switch failOn {
	case "error":
		if worstError {
			return fmt.Errorf("doctor: --fail-on=error triggered")
		}
	case "stale":
		if worstError || worstStale {
			return fmt.Errorf("doctor: --fail-on=stale triggered")
		}
	default:
		return fmt.Errorf("doctor: unknown --fail-on value %q (valid: stale, error)", failOn)
	}
	return nil
}

// collectCacheReport opens the local store, reads per-resource sync state,
// and returns a map summarising cache health. Never panics on missing DB
// or open failure; returns a map with status=unknown or status=error so the
// caller can render and agents can interpret.
//
// staleAfterSpec is the CLI's configured threshold (e.g. "6h"); empty means
// use the runtime default. The default is deliberately conservative (6h)
// because the alternative is no freshness story at all.
func collectCacheReport(staleAfterSpec string) map[string]any {
	report := map[string]any{}
	dbPath := defaultDBPath("salesforce-headless-360-pp-cli")
	report["db_path"] = dbPath

	fi, err := os.Stat(dbPath)
	if err != nil {
		if os.IsNotExist(err) {
			report["status"] = "unknown"
			report["hint"] = "Database not created yet; run 'salesforce-headless-360-pp-cli sync' to hydrate."
			return report
		}
		report["status"] = "error"
		report["error"] = err.Error()
		return report
	}
	report["db_bytes"] = fi.Size()

	s, err := store.Open(dbPath)
	if err != nil {
		report["status"] = "error"
		report["error"] = err.Error()
		return report
	}
	defer s.Close()

	if v, verr := s.SchemaVersion(); verr == nil {
		report["schema_version"] = v
	}
	if auditHealth, herr := trust.LocalBundleAuditHealth(s.DB()); herr == nil {
		report["bundle_audit"] = auditHealth
	}

	staleAfter := 6 * time.Hour
	if staleAfterSpec != "" {
		if d, derr := time.ParseDuration(staleAfterSpec); derr == nil {
			staleAfter = d
		}
	}

	rows, qerr := s.DB().Query(`SELECT resource_type, COALESCE(total_count, 0), last_synced_at FROM sync_state ORDER BY resource_type`)
	if qerr != nil {
		// sync_state may not exist on a fresh DB that has migrated but not
		// yet had any sync runs — treat as unknown rather than error.
		report["status"] = "unknown"
		report["hint"] = "No sync state recorded; run 'salesforce-headless-360-pp-cli sync' to populate."
		return report
	}
	defer rows.Close()

	var resources []map[string]any
	fresh := true
	haveAny := false
	oldest := time.Duration(0)
	for rows.Next() {
		var rtype string
		var count int64
		var lastSynced sql.NullTime
		if err := rows.Scan(&rtype, &count, &lastSynced); err != nil {
			continue
		}
		r := map[string]any{"type": rtype, "rows": count}
		if lastSynced.Valid {
			haveAny = true
			r["last_synced_at"] = lastSynced.Time.UTC().Format(time.RFC3339)
			age := time.Since(lastSynced.Time)
			r["staleness"] = age.Round(time.Minute).String()
			if age > staleAfter {
				fresh = false
			}
			if age > oldest {
				oldest = age
			}
		} else {
			r["staleness"] = "never"
			fresh = false
		}
		resources = append(resources, r)
	}
	report["resources"] = resources
	report["stale_after"] = staleAfter.String()

	switch {
	case !haveAny && len(resources) == 0:
		report["status"] = "unknown"
		report["hint"] = "sync_state is empty; run 'salesforce-headless-360-pp-cli sync' to hydrate."
	case fresh:
		report["status"] = "fresh"
	default:
		report["status"] = "stale"
		report["oldest_age"] = oldest.Round(time.Minute).String()
		report["hint"] = "Some resources are older than stale_after; run 'salesforce-headless-360-pp-cli sync' to refresh."
	}
	return report
}

func renderCacheReport(w io.Writer, rep map[string]any) {
	status, _ := rep["status"].(string)
	indicator := green("OK")
	switch status {
	case "stale":
		indicator = yellow("WARN")
	case "error":
		indicator = red("FAIL")
	case "unknown":
		indicator = yellow("INFO")
	}
	fmt.Fprintf(w, "  %s Cache: %s\n", indicator, status)
	if v, ok := rep["db_path"]; ok {
		fmt.Fprintf(w, "    db_path: %v\n", v)
	}
	if v, ok := rep["schema_version"]; ok {
		fmt.Fprintf(w, "    schema_version: %v\n", v)
	}
	if v, ok := rep["db_bytes"]; ok {
		fmt.Fprintf(w, "    db_bytes: %v\n", v)
	}
	if v, ok := rep["stale_after"]; ok {
		fmt.Fprintf(w, "    stale_after: %v\n", v)
	}
	if v, ok := rep["oldest_age"]; ok {
		fmt.Fprintf(w, "    oldest_age: %v\n", v)
	}
	if resourcesAny, ok := rep["resources"]; ok {
		if resources, ok := resourcesAny.([]map[string]any); ok && len(resources) > 0 {
			fmt.Fprintf(w, "    resources:\n")
			for _, r := range resources {
				rtype, _ := r["type"].(string)
				rows := r["rows"]
				staleness, _ := r["staleness"].(string)
				fmt.Fprintf(w, "      - %s: %v rows, %s\n", rtype, rows, staleness)
			}
		}
	}
	if auditAny, ok := rep["bundle_audit"].(trust.BundleAuditHealth); ok {
		fmt.Fprintf(w, "    bundle_audit: %s total=%d ok=%d failed=%d pending=%d\n", auditAny.Status, auditAny.Total, auditAny.OK, auditAny.Failed, auditAny.Pending)
		if auditAny.LastError != "" {
			fmt.Fprintf(w, "    bundle_audit_last_error: %s\n", auditAny.LastError)
		}
	}
	if hint, ok := rep["hint"]; ok {
		fmt.Fprintf(w, "    hint: %v\n", hint)
	}
}
